#include<bits/stdc++.h>using namespace std;int n,l[300010],r[300010],ans=0;struct node{	int l,r;}prefix[300010],suffix[300010];int main(){	cin>>n;	for(int i=1;i<=n;i++) cin>>l[i]>>r[i];	prefix[1].l=l[1];prefix[1].r=r[1];	for(int i=2;i<=n;i++){		prefix[i].l=max(prefix[i-1].l,l[i]);		prefix[i].r=min(prefix[i-1].r,r[i]);		if(prefix[i].l>prefix[i].r){			prefix[i].l=0;prefix[i].r=0;		}	}	suffix[n].l=l[n];suffix[n].r=r[n];	for(int i=n-1;i>=1;i--){		suffix[i].l=max(suffix[i+1].l,l[i]);		suffix[i].r=min(suffix[i+1].r,r[i]);		if(suffix[i].l>suffix[i].r){			suffix[i].l=0;suffix[i].r=0;		}	}	ans=suffix[2].r-suffix[2].l;	for(int i=2;i<=n-1;i++){		int sl=max(prefix[i-1].l,suffix[i+1].l),sr=min(prefix[i-1].r,suffix[i+1].r);		ans=max(ans,max(0,sr-sl));	}	ans=max(ans,prefix[n-1].r-prefix[n-1].l);	cout<<ans;	return 0;}